/// <summary>
/// Code Extension of Form [InventJournalMovement].
/// </summary>
[ExtensionOf(formStr(InventJournalMovement))]
public final class KJP_SM_InventJournalMovementFormCls_Extension
{
}

Method.Source:
    /// <summary>
    /// init
    /// </summary>
    public void init()
    {
        next init();

        str companyCode = KJP_CM_GeneralPurposeMaster::find(
            KJP_CM_ConstantHelper::KJP_SM_DecimalChangeTargetCompanyCodeKey,
            curExt()).DestinationCode;

        if (companyCode)
        {
            FormRealControl inventQty = this.control(this.controlId(formControlStr(InventJournalMovement, InventJournalTrans_Qty)));
            inventQty.noOfDecimals(3, AutoMode::Fixed);
        }
    }

    /// <summary>
    /// Set whether the item is editable based on HospitalControlFlg.
    /// </summary>
    public void kjp_sm_allowEditByKJPSMHospitalControlFlg()
    {
        // 払出制御フラグが「はい」の場合は、「払出先」を編集可能としプルダウンよりコードを選択するかコードを直接入力することが可能だが、未登録も可能。
        // 払出制御フラグが「いいえ」の場合は、「払出先」「払出先名称」「払出先住所」「払出先電話番号」「払出先郵便番号」は編集不可。
        boolean allowEdit = inventJournalTable.kjp_sm_isKJPSMHospitalControlFlgOn();

        this.kjp_sm_setAllowEdit(inventJournalTable_ds, fieldNum(InventJournalTable, KJPSMHospitalCode), allowEdit);
        this.kjp_sm_setAllowEdit(inventJournalTable_ds, fieldNum(InventJournalTable, KJPSMHospitalName), allowEdit);
        this.kjp_sm_setAllowEdit(inventJournalTable_ds, fieldNum(InventJournalTable, KJPSMHospitalAddress), allowEdit);
        this.kjp_sm_setAllowEdit(inventJournalTable_ds, fieldNum(InventJournalTable, KJPSMHospitalPhoneNumber), allowEdit);
        this.kjp_sm_setAllowEdit(inventJournalTable_ds, fieldNum(InventJournalTable, KJPSMHospitalPostalCode), allowEdit);
    }

    /// <summary>
    /// Set whether the item is editable based on HospitalCode.
    /// </summary>
    public void kjp_sm_allowEditByKJPSMHospitalCode()
    {
        // 払出制御フラグが「いいえ」の場合は、下記の処理不要、返却する
        if (!inventJournalTable.kjp_sm_isKJPSMHospitalControlFlgOn())
        {
            return;
        }

        // 「払出先」が未登録の場合は、「払出先名称」、「払出先住所」、「払出先電話番号」、「払出先郵便番号」の直接入力が可能。
        // 「払出先」を選択orコードを登録した場合は、「払出先名称」「払出先住所」「払出先電話番号」「払出先郵便番号」を営業病医院マスタから値を取得し該当項目にセットし編集不可とする。
        boolean allowEdit = !inventJournalTable.kjp_sm_isKJPSMHospitalCodeInputted();

        this.kjp_sm_setAllowEdit(inventJournalTable_ds, fieldNum(InventJournalTable, KJPSMHospitalName), allowEdit);
        this.kjp_sm_setAllowEdit(inventJournalTable_ds, fieldNum(InventJournalTable, KJPSMHospitalAddress), allowEdit);
        this.kjp_sm_setAllowEdit(inventJournalTable_ds, fieldNum(InventJournalTable, KJPSMHospitalPhoneNumber), allowEdit);
        this.kjp_sm_setAllowEdit(inventJournalTable_ds, fieldNum(InventJournalTable, KJPSMHospitalPostalCode), allowEdit);
    }

/// <summary>
/// Set whether the item is editable.
/// </summary>
/// <param name = "_dataSource">FormDataSource</param>
/// <param name = "_fieldId">FieldId</param>
/// <param name = "_allowEdit">boolean</param>
public void kjp_sm_setAllowEdit(FormDataSource _dataSource, FieldId _fieldId, boolean _allowEdit)
{
    FormDataObject formDataObject = _dataSource.object(_fieldId);
    formDataObject.allowEdit(_allowEdit);
    formDataObject.skip(!_allowEdit);
}

/// <summary>
/// Set whether the item is editable and mandatory.
/// </summary>
/// <param name = "_dataSource">FormDataSource</param>
/// <param name = "_fieldId">FieldId</param>
/// <param name = "_allowEdit">boolean</param>
public void kjp_sm_setAllowEditAndMandatory(FormDataSource _dataSource, FieldId _fieldId, boolean _allowEdit)
{
    FormDataObject formDataObject = _dataSource.object(_fieldId);
    formDataObject.allowEdit(_allowEdit);
    formDataObject.skip(!_allowEdit);
    formDataObject.mandatory(_allowEdit);
}
